import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from './api';
import { statusLabels } from './constants';

function formatProtocol(complaint) {
  if (complaint?.protocol) return complaint.protocol;
  const year = complaint?.created_at ? new Date(complaint.created_at).getFullYear() : new Date().getFullYear();
  return `GRC-${year}-${String(complaint?.id || 0).padStart(6, '0')}`;
}

function formatDate(value) {
  if (!value) return 'Não informado';
  return new Intl.DateTimeFormat('pt-BR', {
    dateStyle: 'short',
    timeStyle: 'short'
  }).format(new Date(value));
}

function ComplaintDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [complaint, setComplaint] = useState(null);
  const [comment, setComment] = useState('');
  const [status, setStatus] = useState('aberta');
  const [feedback, setFeedback] = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const protocol = useMemo(() => formatProtocol(complaint), [complaint]);

  const loadComplaint = useCallback(async () => {
    setLoading(true);
    setFeedback('');

    try {
      const res = await api.get(`/complaints/${id}`);
      setComplaint(res.data);
      setComment(res.data.operator_comment || '');
      setStatus(res.data.status || 'aberta');
    } catch (error) {
      setFeedback('Não foi possível carregar esta reclamação.');
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    loadComplaint();
  }, [loadComplaint]);

  const handleSave = async () => {
    setSaving(true);
    setFeedback('');

    try {
      await api.patch(`/complaints/${id}`, {
        status,
        operator_comment: comment
      });
      setFeedback('Reclamação atualizada com sucesso.');
      await loadComplaint();
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Erro ao atualizar reclamação.');
    } finally {
      setSaving(false);
    }
  };

  const handleClose = async () => {
    setSaving(true);
    setFeedback('');

    try {
      await api.patch(`/complaints/${id}`, {
        status: 'resolvida',
        operator_comment: comment
      });
      setStatus('resolvida');
      setFeedback('Reclamação fechada com sucesso.');
      await loadComplaint();
    } catch (error) {
      setFeedback(error.response?.data?.error || 'Erro ao fechar reclamação.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <main className="app-page">
        <section className="management-panel">
          <p className="empty-state">Carregando reclamação...</p>
        </section>
      </main>
    );
  }

  if (!complaint) {
    return (
      <main className="app-page">
        <section className="restricted-panel">
          <p className="eyebrow">Gestão de reclamações</p>
          <h1>Reclamação não encontrada</h1>
          <p>Volte para a lista e selecione outra reclamação.</p>
          <button className="primary-action" onClick={() => navigate('/gestao')}>
            Voltar para gestão
          </button>
        </section>
      </main>
    );
  }

  return (
    <main className="app-page">
      <header className="page-heading">
        <div>
          <p className="eyebrow">Gestão de reclamações</p>
          <h1>{protocol}</h1>
          <p>{complaint.clinic_name || 'Clínica não informada'} · {complaint.city || 'Cidade'} / {complaint.state || 'UF'}</p>
        </div>

        <div className="heading-actions">
          <button className="outline-action" onClick={() => navigate('/gestao')}>
            Voltar para gestão
          </button>
          <button className="outline-action" onClick={() => navigate('/home')}>
            Home
          </button>
        </div>
      </header>

      <section className="complaint-detail-grid">
        <article className="detail-card">
          <div className="detail-title-row">
            <div>
              <p className="eyebrow">Status atual</p>
              <h2>{statusLabels[complaint.status] || complaint.status || 'Aberta'}</h2>
            </div>
            <span className={`status-pill ${complaint.status || 'aberta'}`}>
              {statusLabels[complaint.status] || 'Aberta'}
            </span>
          </div>

          <dl className="meta-grid">
            <div>
              <dt>Paciente</dt>
              <dd>{complaint.patient_name || 'Não informado'}</dd>
            </div>
            <div>
              <dt>Telefone</dt>
              <dd>{complaint.patient_phone || 'Não informado'}</dd>
            </div>
            <div>
              <dt>Tipo</dt>
              <dd>{complaint.complaint_type || 'Não informado'}</dd>
            </div>
            <div>
              <dt>Canal</dt>
              <dd>{complaint.channel || 'Não informado'}</dd>
            </div>
            <div>
              <dt>Serviço</dt>
              <dd>{complaint.service_type || 'Não informado'}</dd>
            </div>
            <div>
              <dt>Região</dt>
              <dd>{complaint.region || 'Não informada'}</dd>
            </div>
            <div>
              <dt>Criada em</dt>
              <dd>{formatDate(complaint.created_at)}</dd>
            </div>
            <div>
              <dt>Atualizada em</dt>
              <dd>{formatDate(complaint.updated_at)}</dd>
            </div>
          </dl>
        </article>

        <article className="detail-card">
          <p className="eyebrow">Relato</p>
          <p className="complaint-description">{complaint.description || 'Sem descrição registrada.'}</p>

          {complaint.attachment_url && (
            <a className="attachment-link" href={complaint.attachment_url} target="_blank" rel="noreferrer">
              Ver anexo da reclamação
            </a>
          )}
        </article>

        <article className="detail-card detail-actions-card">
          <p className="eyebrow">Tratativa</p>
          <label>
            Status da reclamação
            <select className="field" value={status} onChange={(event) => setStatus(event.target.value)}>
              <option value="aberta">Aberta</option>
              <option value="em_andamento">Em andamento</option>
              <option value="resolvida">Fechada</option>
            </select>
          </label>

          <label>
            Comentários da gestão
            <textarea
              className="field textarea"
              value={comment}
              onChange={(event) => setComment(event.target.value)}
              placeholder="Registre contatos, evidências, retorno da unidade e decisão final."
            />
          </label>

          {feedback && <p className="form-feedback">{feedback}</p>}

          <div className="row-actions">
            <button className="secondary-action" onClick={handleSave} disabled={saving}>
              {saving ? 'Salvando...' : 'Salvar tratativa'}
            </button>
            <button className="primary-action" onClick={handleClose} disabled={saving}>
              Fechar reclamação
            </button>
          </div>
        </article>
      </section>
    </main>
  );
}

export default ComplaintDetail;
